#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A,B; scanf("%lld %lld", &A, &B);
        if(A==B || B>=2*A) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

